// /search_records returns {generated_sql_query, output} where output is a JSON string array of rows
// or {detail: 'Please provide at least one search name.'}
const body = $json.body || $json;
const query = $('Query Webhook').item.json.body.query || '';

// Handle error case
if (body.detail) {
  return [{ json: { results: [], count: 0, voice_response: 'Please provide a name to search for.', query } }];
}

// Parse output - it's a JSON string of row objects
let rows = [];
try {
  const raw = body.output;
  rows = typeof raw === 'string' ? JSON.parse(raw) : (Array.isArray(raw) ? raw : []);
} catch(e) { rows = []; }

const count = rows.length;
let speak = count === 0
  ? 'I found no matching records.'
  : `I found ${count} result${count === 1 ? '' : 's'}.`;

rows.slice(0, 5).forEach((r, i) => {
  const fn = r.first_name || r.firstname || '';
  const ln = r.last_name || r.lastname || '';
  const name = [fn, ln].filter(Boolean).join(' ') || r.record_text || 'Unknown';
  speak += ` Record ${i + 1}: ${name}.`;
});

return [{ json: { results: rows, count, voice_response: speak, query } }];
